AD_UPDATE_PINSTANCE(p_PInstance_ID, NULL, 'N', v_Result, v_Message) ; END; --BODY EXCEPTION WHEN OTHERS THEN DBMS_OUTPUT.PUT_LINE('MRP_PURCHASE_RUN exception: ' || v_ResultStr) ; v_ResultStr:= '@ERROR=' || SQLERRM; DBMS_OUTPUT.PUT_LINE(v_ResultStr) ; ROLLBACK; AD_UPDATE_PINSTANCE(p_PInstance_ID, NULL, 'N', 0, v_ResultStr) ; -- RETURN; END SSMRPS_CREATE_SIMULATION
